#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n,m,dp[100001],pos=0,w[1000001],v[1000001];

int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		int v1,w1,s,k=1;
        cin>>v1>>w1>>s;
        while(k<=s){
            v[++pos] =v1*k;
            w[pos]=w1*k;
            s-=k;
            k*=2;
        }
        if(s){
            v[++pos]=v1*s;
            w[pos]=w1*s;
        }
    }for(int i=1;i<=pos;i++){
        for(int j=m;j>=w[i];j--){
            dp[j]=max(dp[j],dp[j-w[i]]+v[i]);
        }
    }
	cout<<dp[m];
	return 0;
}
